import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    parser = ET.XMLParser(resolve_entities=False)
    tree = ET.parse(file_path, parser=parser)
    root = tree.getroot()
    
    settings = {}
    for child in root:
        settings[child.tag] = child.text
    
    return settings